const trigger = $('Workflow Trigger').first().json;
const targetOrderNumber = String(trigger.order_number || '').replace(/\D/g, '');
const targetPhone = String(trigger.phone || '').replace(/\D/g, '');
const docs = $input.all().map((entry) => entry.json).filter((entry) => entry && entry.document);

const parseField = (field) => {
  if (!field || typeof field !== 'object') return field;
  if (field.stringValue !== undefined) return field.stringValue;
  if (field.integerValue !== undefined) return Number(field.integerValue);
  if (field.doubleValue !== undefined) return Number(field.doubleValue);
  if (field.booleanValue !== undefined) return field.booleanValue;
  if (field.timestampValue !== undefined) return field.timestampValue;
  if (field.nullValue !== undefined) return null;
  if (field.arrayValue) return (field.arrayValue.values || []).map(parseField);
  if (field.mapValue) {
    const obj = {};
    for (const [key, value] of Object.entries(field.mapValue.fields || {})) {
      obj[key] = parseField(value);
    }
    return obj;
  }
  return null;
};

const normalizePhone = (value = '') => String(value).replace(/\D/g, '');
const formatCurrency = (value) => {
  const amount = Number(value || 0);
  return amount.toLocaleString('pt-BR', { style: 'currency', currency: 'BRL' });
};
const describeStatus = (saleStatus, orderStatus) => {
  if (saleStatus === 'payment_sent') {
    return 'aguardando pagamento';
  }
  switch (orderStatus) {
    case 'awaiting_processing':
    case 'separating':
      return 'aguardando processamento';
    case 'preparing':
      return 'em preparacao';
    case 'packing':
      return 'embalando';
    case 'awaiting_pickup':
      return 'aguardando retirada';
    case 'ready_for_pickup':
    case 'ready_for_shipping':
    case 'ready':
      return 'pronto para envio ou retirada';
    case 'shipped':
      return 'enviado';
    case 'completed':
      return 'concluido';
    default:
      return saleStatus === 'confirmed' ? 'em andamento' : 'aguardando definicao';
  }
};
const formatDate = (value = '') => {
  const parsed = Date.parse(String(value || '').trim());
  if (Number.isNaN(parsed)) return '';
  return new Date(parsed).toLocaleString('pt-BR');
};
const summarizeItems = (items) => {
  if (!Array.isArray(items) || items.length === 0) return 'sem itens detalhados';
  return items
    .slice(0, 4)
    .map((item) => `${item.quantity || 1}x ${String(item.product_name || item.name || 'item').trim()}`)
    .join('; ');
};

const sales = docs
  .map((raw) => {
    const fields = raw.document.fields || {};
    const items = parseField(fields.items) || [];
    const publicOrderNumber = String(parseField(fields.public_order_number) || '').trim();
    const customerWhatsapp = normalizePhone(parseField(fields.customer_whatsapp) || '');
    const status = String(parseField(fields.status) || '').trim();
    const orderStatus = String(parseField(fields.order_status) || '').trim();
    return {
      sale_id: raw.document.name.split('/').pop(),
      order_number: publicOrderNumber,
      order_number_label: publicOrderNumber ? `#${publicOrderNumber}` : '',
      status,
      order_status: orderStatus,
      customer_id: String(parseField(fields.customer_id) || '').trim(),
      customer_whatsapp: customerWhatsapp,
      total: Number(parseField(fields.total) || 0),
      customer_name: String(parseField(fields.customer_name) || '').trim(),
      items,
      items_summary: summarizeItems(items),
      created_at: String(parseField(fields.created_at) || '').trim(),
      current_status_label: describeStatus(status, orderStatus),
    };
  })
  .filter((sale) => sale.status && sale.status !== 'cancelled')
  .filter((sale) => !targetPhone || !sale.customer_whatsapp || sale.customer_whatsapp === targetPhone)
  .sort((a, b) => String(b.created_at || '').localeCompare(String(a.created_at || '')));

const compactOrders = sales.slice(0, 10).map((sale) => ({
  sale_id: sale.sale_id,
  order_number: sale.order_number,
  order_number_label: sale.order_number_label,
  status: sale.status,
  order_status: sale.order_status,
  current_status_label: sale.current_status_label,
  total: sale.total,
  total_label: formatCurrency(sale.total),
  created_at: sale.created_at,
  created_at_label: formatDate(sale.created_at),
  items_summary: sale.items_summary,
}));

let matchedSale = null;
if (targetOrderNumber) {
  matchedSale = sales.find((sale) => sale.order_number === targetOrderNumber) || null;
}
if (!matchedSale) {
  matchedSale = sales[0] || null;
}

if (!matchedSale) {
  return [{
    json: {
      success: false,
      found: false,
      total_orders_found: 0,
      recent_orders: [],
      recent_orders_summary: 'Nenhum pedido encontrado para este cliente.',
      message: 'Nenhum pedido encontrado para este cliente.'
    }
  }];
}

const recentOrdersSummary = compactOrders.length > 0
  ? compactOrders
      .map((order) => `${order.order_number_label || 'Pedido sem numero'} em ${order.created_at_label || 'data indisponivel'}: ${order.current_status_label}; total ${order.total_label}; itens ${order.items_summary}`)
      .join(' | ')
  : 'Nenhum pedido anterior encontrado.';

return [{
  json: {
    success: true,
    found: true,
    ...matchedSale,
    total_label: formatCurrency(matchedSale.total),
    created_at_label: formatDate(matchedSale.created_at),
    total_orders_found: sales.length,
    recent_orders: compactOrders,
    recent_orders_summary: recentOrdersSummary,
    matched_order_items_summary: matchedSale.items_summary,
    latest_order_number_label: compactOrders[0]?.order_number_label || matchedSale.order_number_label,
    latest_order_status_label: compactOrders[0]?.current_status_label || matchedSale.current_status_label,
  }
}];
